class Solution:
    def generateValidStrings(self, n: int, k: int):
        result = []
        for mask in range(1 << n):
            bits = [(mask >> i) & 1 for i in range(n)]
            ok = True
            cost = 0
            for i in range(n):
                if bits[i] == 1:
                    cost += i
                    if i + 1 < n and bits[i + 1] == 1:
                        ok = False
                        break
            if ok and cost <= k:
                s = ''.join(str(b) for b in bits)
                result.append(s)
        return result

