class Solution:
    def generateValidStrings(self, n: int, k: int):
        result = []
        def rec(i, prevOne, cost, chars):
            if cost > k:
                return
            if i == n:
                result.append(''.join(chars))
                return
            chars.append('0')
            rec(i + 1, False, cost, chars)
            chars.pop()
            if not prevOne and cost + i <= k:
                chars.append('1')
                rec(i + 1, True, cost + i, chars)
                chars.pop()
        rec(0, False, 0, [])
        return result

