var generateValidStrings = function(n, k) {
    const result = [];
    const chars = [];
    function rec(i, prevOne, cost) {
        if (cost > k) return;
        if (i === n) {
            result.push(chars.join(''));
            return;
        }
        chars.push('0');
        rec(i + 1, false, cost);
        chars.pop();
        if (!prevOne && cost + i <= k) {
            chars.push('1');
            rec(i + 1, true, cost + i);
            chars.pop();
        }
    }
    rec(0, false, 0);
    return result;
};
